generated_oml:
// ==================== C3: Physical Sensing Components ====================

// Motor position encoder
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor position encoder mounted on the permanent‑magnet synchronous motor of the first axis."
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

// Gearbox position encoder (secondary encoder behind the gearbox)
instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary position encoder mounted behind the gearwheel gearbox of the first axis."
    DTDFVocab:producedData GearboxEncoderDataTransmitted
]

// Motor current sensor
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring the motor input current I_M."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

// Torque estimator (derived from current sensor)
instance TorqueEstimator : DTDFVocab:SensingComponent [
    base:desc "Computation unit deriving torque τ from motor current I_M and motor constants."
    DTDFVocab:producedData TorqueDataTransmitted
]

// Angular velocity estimator (derived from encoders)
instance AngularVelocityEstimator : DTDFVocab:SensingComponent [
    base:desc "Computation unit deriving angular velocity ω from motor and gearbox encoder signals."
    DTDFVocab:producedData AngularVelocityDataTransmitted
]

// ==================== C4: Physical‑to‑Virtual Interaction ====================

// Data transmitted by motor encoder
instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

// Data transmitted by gearbox encoder
instance GearboxEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

// Data transmitted by motor current sensor
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// Data transmitted by torque estimator
instance TorqueDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom TorqueEstimator, MotorCurrentSensor
]

// Data transmitted by angular velocity estimator
instance AngularVelocityDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom AngularVelocityEstimator, MotorEncoder, GearboxEncoder
]

// ==================== C10: Models / Data ====================

// Engineering models (SysML)
instance SysMLMotorModel : DTDFVocab:Model [
    base:desc "SysML block definition of the permanent‑magnet synchronous motor for the first axis."
    DTDFVocab:inputTo AssetAdministrationShell
]

instance SysMLGearboxModel : DTDFVocab:Model [
    base:desc "SysML block definition of the gearwheel gearbox."
    DTDFVocab:inputTo AssetAdministrationShell
]

// Simulation models (Simulink)
instance SimulinkFrictionlessDrivetrainModel : DTDFVocab:Model [
    base:desc "MATLAB Simulink model of the friction‑less drivetrain (motor, gearwheel, cycloidal gearbox)."
    DTDFVocab:inputTo SimulinkSimulationTool
]

instance SimulinkCoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Coulomb‑Viscous friction for the drivetrain."
    DTDFVocab:inputTo SimulinkSimulationTool
]

instance SimulinkStribeckFrictionModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Stribeck friction behaviour."
    DTDFVocab:inputTo SimulinkSimulationTool
]

// Data calculation models
instance DataCalcTorqueModel : DTDFVocab:Model [
    base:desc "Processing component that computes torque τ from motor current and constants."
    DTDFVocab:inputTo SimulinkSimulationTool, AssetAdministrationShell
]

instance DataCalcAngularVelocityModel : DTDFVocab:Model [
    base:desc "Processing component that computes angular velocity ω from encoder signals."
    DTDFVocab:inputTo SimulinkSimulationTool, AssetAdministrationShell
]

// Measured data (from sensors)
instance MeasuredMotorPosition : DTDFVocab:Data [
    base:desc "Time‑series of motor shaft angle r_M measured by the motor encoder."
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo MqttBroker, AssetAdministrationShell
]

instance MeasuredGearboxPosition : DTDFVocab:Data [
    base:desc "Time‑series of gearwheel angle r_G measured by the secondary encoder."
    DTDFVocab:fromData GearboxEncoderDataTransmitted
    DTDFVocab:inputTo MqttBroker, AssetAdministrationShell
]

instance MeasuredMotorCurrent : DTDFVocab:Data [
    base:desc "Time‑series of motor input current I_M measured by the current sensor."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MqttBroker, AssetAdministrationShell
]

instance MeasuredTorque : DTDFVocab:Data [
    base:desc "Derived torque τ computed from I_M and motor constants."
    DTDFVocab:fromData TorqueDataTransmitted
    DTDFVocab:inputTo MqttBroker, AssetAdministrationShell
]

instance MeasuredAngularVelocity : DTDFVocab:Data [
    base:desc "Derived angular velocity ω computed from encoder signals."
    DTDFVocab:fromData AngularVelocityDataTransmitted
    DTDFVocab:inputTo MqttBroker, AssetAdministrationShell
]

// Simulated data traces
instance SimulatedMotorPosition : DTDFVocab:Data [
    base:desc "Simulated motor shaft angle ^r_M produced by the friction‑less drivetrain model."
    DTDFVocab:inputTo SimulinkSimulationTool
]

instance SimulatedGearboxPosition : DTDFVocab:Data [
    base:desc "Simulated gearwheel angle ^r_G produced by the friction‑less drivetrain model."
    DTDFVocab:inputTo SimulinkSimulationTool
]

instance SimulatedOutputAngle : DTDFVocab:Data [
    base:desc "Simulated output angle ^r_out of the cycloidal gearbox."
    DTDFVocab:inputTo SimulinkSimulationTool
]

// ==================== C11: Enablers ====================

instance MqttBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker used for live streaming of sensor time‑series from the robot to the digital shadow."
    DTDFVocab:enables RealTimeVisualizationService, FrictionIdentificationService, ParameterSupplyService, ModelValidationService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell (AAS) providing standardized model integration and data exchange."
    DTDFVocab:enables ParameterSupplyService, ModelValidationService
]

instance WebDashboard : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard visualizing real‑time measured vs. simulated behavior and friction components."
    DTDFVocab:enables RealTimeVisualizationService
]

instance SimulinkSimulationTool : DTDFVocab:Enabler [
    base:desc "MATLAB Simulink runtime executing friction and drivetrain simulation models."
    DTDFVocab:enables FrictionIdentificationService, ModelValidationService
]

instance SysMLModelingTool : DTDFVocab:Enabler [
    base:desc "SysML tool used for structural block definition and internal block diagrams of motor, gearwheel and cycloidal gearbox."
    DTDFVocab:enables ParameterSupplyService
]

// ==================== C6: Services ====================

instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Dashboard service visualizing real‑time measured vs. simulated behavior and identified friction components."
    DTDFVocab:provides InsightDriftDetection, ActionRetuneController
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuous multi‑physics‑aware identification of static, kinetic and viscous friction parameters."
    DTDFVocab:provides InsightFrictionParameters, ActionUpdateFrictionParameters
]

instance ParameterSupplyService : DTDFVocab:Service [
    base:desc "Supplies quantified friction parameters to the robot controller to improve motion accuracy."
    DTDFVocab:provides InsightFrictionParameters
]

instance ModelValidationService : DTDFVocab:Service [
    base:desc "Compares simulated traces with measured data for validation and model refinement."
    DTDFVocab:provides InsightDriftDetection
]

// ==================== C17: Insights / Actions ====================

instance InsightFrictionParameters : DTDFVocab:Insight [
    base:desc "Quantitative static, kinetic and viscous friction parameters identified by the digital shadow."
]

instance InsightDriftDetection : DTDFVocab:Insight [
    base:desc "Real‑time detection of discrepancies between measured and simulated behavior indicating wear‑induced drift."
]

instance ActionRetuneController : DTDFVocab:Action [
    base:desc "Engineers decide to retune the robot controller based on detected drift."
    DTDFVocab:IsAutomatic false
]

instance ActionUpdateFrictionParameters : DTDFVocab:Action [
    base:desc "Automatic update of friction parameters in the controller after identification."
    DTDFVocab:IsAutomatic true
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The digital shadow consists of a Purpose (FrictionDerivation), the Asset (MABI robot first axis), Processing components (Simulation M, Simulation GW, Simulation GB) that consume measured DataTraces and apply simulation models to produce simulated DataTraces, all instantiated from the Digital Shadow Reference Model. The resulting data are visualized in a unified dashboard for friction analysis."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital shadow is created and operated during the runtime (operational) phase of the robot, using live data to continuously identify friction while the robot is machining."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability is enforced by linking each DataTrace to its originating sensor, processing component and simulation model. Validation is performed by comparing simulated friction‑subtracted outputs with measured reference data. Both white‑box analytical friction models and black‑box data‑driven models are continuously updated to maintain accuracy during operation."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transmitted over MQTT; the Asset Administration Shell (AAS) is used to expose model metadata and enable integration with the processing components. No bidirectional protocol is defined for control feedback."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The approach follows the Digital Shadow Reference Model (UML class diagram), uses SysML (an OMG standard) for system architecture, and adopts the Asset Administration Shell (AAS) standard for Industry 4.0 asset representation."
]
